#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
_i128 n,A,B,a2,b2;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
_i128 exGCD(_i128 a,_i128 b,_i128 &x,_i128 &y){
    if(b==0){x=1,y=0;return a;}
    _i128 X,Y;
    _i128 yu=exGCD(b,a%b,X,Y);
    x=Y,y=X-Y*(a/b);
    return yu;
}
_i128 QP(_i128 x,_i128 y,_i128 mod){
    _i128 as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
int main(){
    n=read();
    A=read(),B=read();
    for(int i=1;i<n;i++){
        a2=read(),b2=read();
        _i128 x=0,y=0;
        _i128 g=exGCD(A,a2,x,y);
        x=(B-b2)/g*x;
        B=B-A*x;
        A=a2/g*A;
        B=(B+A)%A;
    }cout<<(LL)((B+A)%A)<<"\n";
    return 0;
}
